analyze the function names and suggest the best name for each function according to Python style guides like PEP8. List the function with the suggested new names and explanations. Python 3.12 Code: import ctypes import logging import os import shutil import subprocess import threading import time import tkinter as tk from collections import defaultdict from concurrent.futures import ThreadPoolExecutor, Future from contextlib import contextmanager from pathlib import Path from queue import Queue from tkinter import filedialog from tkinter import ttk from typing import Any, Callable, Optional, Sequence, Union, Generator, cast from dataclasses import dataclass, field import tempfile import numpy as np from PIL import Image # --- Configuration --- @dataclass class SharedState: """Represents the shared state across the application.""" processed_files_lock: threading.Lock = field(default_factory=threading.Lock) processed_files_count: int = 0 total_files_count: int = 0 log_message_queue: Queue[str] = field(default_factory=Queue) tab_messages: dict[str, list[str]] = field( default_factory=lambda: {"Log": [], "Black": [], "White": [], "Color": []} ) stop_event: threading.Event = field(default_factory=threading.Event) class Config: """Configuration settings for the image processing application.""" SCRIPT_DIR: Path = Path(__file__).parent.resolve() INPUT_FOLDER: Path = Path(os.getenv("INPUT_FOLDER", SCRIPT_DIR / "1. Input")) OUTPUT_FOLDER: Path = Path(os.getenv("OUTPUT_FOLDER", SCRIPT_DIR / "2. Output")) DEFAULT_INPUT_FOLDER: Path = INPUT_FOLDER DEFAULT_OUTPUT_FOLDER: Path = OUTPUT_FOLDER DEFAULT_RENAME_PATTERN: str = "{Filename}" # Executable Paths IMAGEMAGICK: Path = Path( os.getenv( "IMAGEMAGICK", "D:/Bilder/Python/0. Code/Requirements/ImageMagick.exe" ) ) FFMPEG: Path = Path( os.getenv("FFMPEG", "D:/Bilder/Python/0. Code/Requirements/ffmpeg.exe") ) # Supported File Extensions AUDIO_EXTENSIONS: set[str] = {".mka", ".mpga", ".mp3", ".aac", ".flac", ".opus", ".ogg"} IMAGE_EXTENSIONS: set[str] = {".png", ".jpg", ".jpeg", ".webp"} VIDEO_EXTENSIONS: set[str] = {".mkv", ".mp4"} # Display and Formatting Constants SEPARATOR_LENGTH: int = 310 PADDING_LENGTH: int = 82 PROGRESS_BAR_LENGTH: int = 100 # Default Resize Options DEFAULT_RESIZE_MODE: str = "Shortest Side" DEFAULT_RESIZE_WIDTH: int = 0 DEFAULT_RESIZE_HEIGHT: int = 0 DEFAULT_RESIZE_SIDE: int = 1600 DEFAULT_RESIZE_FORMAT: str = "png" # Color Detection Thresholds COLORDIFF_THRESHOLD: int = 5 FRACTION_COLORED_PIXELS_THRESHOLD: float = 0.03 @classmethod def setup(cls) -> None: """Create output directory and configure logging settings.""" cls.OUTPUT_FOLDER.mkdir(parents=True, exist_ok=True) logging.getLogger("PIL").setLevel(logging.WARNING) @classmethod def initialize(cls) -> SharedState: """Initialize configuration and return shared state.""" cls.setup() return SharedState() @contextmanager def create_temp_folder() -> Generator[Path, None, None]: """Yield a temporary folder within the output directory.""" with tempfile.TemporaryDirectory(dir=Config.OUTPUT_FOLDER) as temp_dir: yield Path(temp_dir) # --- Logging --- def log_errors(error_queue: Queue[tuple[Path, list[str]]]) -> None: """Log errors from the error queue.""" error_dict: dict[Path, list[str]] = defaultdict(list) while not error_queue.empty(): file_path, error_messages = error_queue.get() error_dict[file_path].extend(error_messages) if error_dict: shared_state.log_message_queue.put("UPDATE_LOG") for file_path in sorted(error_dict.keys()): shared_state.log_message_queue.put(f"{file_path.resolve()}") shared_state.log_message_queue.put("") for error_message in sorted(error_dict[file_path]): log_error(error_message) shared_state.log_message_queue.put("") def log_and_execute( choice: str, label: str, function: Callable[..., Any], *args: Any ) -> None: """Log the execution of a function and run it in a separate thread.""" def run_in_thread() -> None: start_time = time.time() separator = "-" * Config.SEPARATOR_LENGTH shared_state.log_message_queue.put(f"{separator}
{label}
{separator}
") try: total_files = function(*args) except FileNotFoundError as e: log_error(str(e)) total_files = 0 except (OSError, ValueError) as e: log_error(f"An error occurred during '{label}': {e}") total_files = 0 end_time = time.time() execution_time = end_time - start_time shared_state.log_message_queue.put("") image_processor.collect_processing_results(Config.OUTPUT_FOLDER, choice) app.after(0, app.update_final_status, execution_time) app.after(0, app.update_text_area) thread = threading.Thread(target=run_in_thread) thread.start() # --- Utility Functions --- def log_error(message: str) -> None: """Log an error message to the shared state queue.""" shared_state.log_message_queue.put(f"- {message}") def validate_and_load_image(path: Path) -> Optional[Image.Image]: """Validate and load image, return None if invalid.""" try: with Image.open(path) as img: match img.mode: case "P": return img.convert("L") case "L" | "RGB" | "RGBA": return img.copy() case _: return img.convert("RGB") except (OSError, ValueError) as e: log_error(f"Error reading image {path}: {e}") return None def load_image_as_array(path: Path, mode: Optional[str] = None) -> Optional[np.ndarray]: """Load an image and convert it to a NumPy array with error handling.""" img = validate_and_load_image(path) if img is None: return None if mode is not None: img = img.convert(mode) try: return np.array(img) except (OSError, ValueError) as e: log_error(f"Error converting image to array {path}: {e}") return None def convert_png_to_jpg(input_path: Path, output_path: Path) -> None: """Convert a PNG image to JPG format.""" try: with Image.open(input_path) as img: if img.mode not in ("RGB", "L"): img = img.convert("RGB") jpg_path = output_path.with_suffix(".jpg") img.save(jpg_path, format="JPEG", quality=80, subsampling=0) input_path.unlink() except Exception as e: log_error(f"Error converting {input_path} to JPG: {e}") def verify_executable_exists(executable: Path, name: str) -> None: """Check if a given executable is available in the system.""" if not shutil.which(str(executable)): raise FileNotFoundError(f"- {name} executable not found at: {executable}") def increment_processed_count(start_time: float, total_files: int) -> None: """Safely increment the processed files count and update the status.""" with shared_state.processed_files_lock: shared_state.processed_files_count += 1 update_status(start_time, shared_state.processed_files_count, total_files) def renamer(pattern: str, original_filename: str) -> str: """Rename the file based on the provided pattern.""" base, ext = os.path.splitext(original_filename) new_base = pattern.replace("{Filename}", base).strip() # Ensure the new base name is not empty if not new_base: new_base = base # Replace or remove any illegal characters if necessary illegal_chars = r'/:*?"<>|' for char in illegal_chars: new_base = new_base.replace(char, "_") return f"{new_base}{ext}" # --- Process Bar and Multithreading --- def update_status(start_time: float, processed_count: int, total_files: int) -> None: """Update the application's status text with processing details.""" elapsed_time = time.time() - start_time minutes, seconds = divmod(int(elapsed_time), 60) elapsed_time_str = f"{minutes:02d}:{seconds:02d}" start_time_str = time.strftime("%H:%M:%S", time.localtime(start_time)) status_text = ( f"Start Time: {start_time_str} - " f"Processed Files: {processed_count}/{total_files} - " f"Elapsed Time: {elapsed_time_str} Minutes" ) padded_status_text = status_text.ljust(Config.PADDING_LENGTH) app.update_status_text(padded_status_text) def update_elapsed_time( start_time: float, total_files: int, stop_event: threading.Event ) -> None: """Continuously update the elapsed time until the stop event is set.""" while not stop_event.is_set(): update_status(start_time, shared_state.processed_files_count, total_files) time.sleep(1) def start_elapsed_time_thread( start_time: float, total_files: int, stop_event: threading.Event ) -> threading.Thread: """Start a thread to update the elapsed time.""" thread = threading.Thread( target=update_elapsed_time, args=(start_time, total_files, stop_event), daemon=True, ) thread.start() return thread def run_with_thread_pool( tasks: Sequence[Path], process_func: Callable[..., Any], *args: Any ) -> int: """Execute tasks using a thread pool, updating progress and handling errors.""" shared_state.processed_files_count = 0 shared_state.total_files_count = total = len(tasks) start_time = time.time() app.update_progress(0) stop_event = threading.Event() elapsed_time_thread = start_elapsed_time_thread(start_time, total, stop_event) try: with ThreadPoolExecutor() as executor: futures: list[Future] = [ executor.submit(process_func, task, *args) for task in tasks ] for index, future in enumerate(futures, start=1): if shared_state.stop_event.is_set(): for f in futures: f.cancel() break try: future.result() except Exception as e: log_error(f"Error during processing: {e}") finally: progress = (index / total) * 100 app.update_progress(progress) finally: stop_event.set() elapsed_time_thread.join() return total # --- Color Detection And Adjustment --- def is_color_image( img: np.ndarray, diff_threshold: int = Config.COLORDIFF_THRESHOLD, fraction_threshold: float = Config.FRACTION_COLORED_PIXELS_THRESHOLD, ) -> bool: """Determine if an image is color based on RGB channel differences.""" # Check if the image has three channels (RGB) if img.ndim != 3 or img.shape[2] != 3: return False # Calculate the peak-to-peak (max - min) difference across the RGB channels for each pixel max_diff = np.ptp(img, axis=2) # Compute the fraction of pixels where the max difference exceeds the threshold fraction_colored = np.mean(max_diff > diff_threshold) # Determine if the image meets or exceeds the required fraction of colored pixels return fraction_colored >= fraction_threshold def adjust_grayscale_values(img: np.ndarray) -> tuple[np.ndarray, int, int]: """Adjust the values of a grayscale image.""" try: # Calculate modal white value in the range [250, 256) hist_white, bins_white = np.histogram(img[img >= 250], bins=6, range=(250, 256)) modal_white = int(bins_white[np.argmax(hist_white)]) # Calculate modal black value in the range [0, 61) hist_black, bins_black = np.histogram(img[img < 61], bins=61, range=(0, 61)) modal_black = int(bins_black[np.argmax(hist_black)]) # Convert image to float for processing adjusted = img.astype(np.float64) # Create a mask for extreme original values (0 and 255) mask = (img == 0) | (img == 255) # Exclude extreme values from the white adjustment white_adjust_mask = ~mask # Scale image if modal white is not at maximum intensity if modal_white != 255: adjusted[white_adjust_mask] *= 255.0 / modal_white adjusted = np.clip(adjusted, 0, 255) # After white value adjustment, identify new extreme values new_extremes = (adjusted == 0) | (adjusted == 255) # Combine masks to exclude all extreme values from black adjustment total_extremes = mask | new_extremes black_adjust_mask = ~total_extremes # Adjust image based on modal black value if modal_black: adjusted[black_adjust_mask] = ( adjusted[black_adjust_mask] - modal_black ) * (255.0 / (255 - modal_black)) adjusted = np.clip(adjusted, 0, 255) gamma = 1.0 - (modal_black / 255.0) adjusted[black_adjust_mask] = ( np.power(adjusted[black_adjust_mask] / 255.0, gamma) * 255 ) # Round to nearest integer and then convert to uint8 adjusted = np.rint(adjusted).astype(np.uint8) return adjusted, modal_black, modal_white except ValueError as e: log_error(f"Error adjusting values for image: {e}") return img, 0, 255 # --- Image Analysis --- def analyze_images_for_color_properties(image_processor: "ImageProcessor") -> None: """Analyze images in the input folder for color properties.""" image_processor.reset_results() image_files: list[Path] = [ path for path in Config.INPUT_FOLDER.rglob("*") if path.is_file() and path.suffix.lower() in Config.IMAGE_EXTENSIONS ] if not image_files: log_error(f"No image files found in '{Config.INPUT_FOLDER}'") return with create_temp_folder() as temp_folder: start_time = time.time() run_with_thread_pool(image_files, analyze_file, start_time, len(image_files)) def analyze_file(path: Path, start_time: float, total: int) -> None: """Analyze an image to classify it as color or grayscale.""" img_array = load_image_as_array(path) if img_array is None: increment_processed_count(start_time, total) return subfolder = path.parent.relative_to(Config.INPUT_FOLDER).as_posix() filename = path.name if is_color_image(img_array): image_processor.color_results[subfolder].append(filename) else: # Load the image as grayscale before adjusting values img_gray = load_image_as_array(path, mode='L') if img_gray is None: increment_processed_count(start_time, total) return adjusted, modal_black, modal_white = adjust_grayscale_values(img_gray) if modal_black: image_processor.black_results[subfolder].append((filename, modal_black)) if modal_white != 255: image_processor.white_results[subfolder].append((filename, modal_white)) increment_processed_count(start_time, total) def find_color_images(image_processor: "ImageProcessor") -> None: """Find and move color images to the output folder.""" image_processor.reset_results() image_extensions: set[str] = {ext.lower() for ext in Config.IMAGE_EXTENSIONS} tasks: list[Path] if not ( tasks := [ path for path in Config.INPUT_FOLDER.rglob("*") if path.is_file() and path.suffix.lower() in image_extensions ] ): log_error(f"No image files found in '{Config.INPUT_FOLDER}'") return with create_temp_folder(): run_with_thread_pool( tasks, move_color_image_file, time.time(), len(tasks), image_processor ) def move_color_image_file( path: Path, start_time: float, total_files: int, image_processor: "ImageProcessor" ) -> None: """Move a color image file to the output folder with renaming and update processing status.""" img_array = load_image_as_array(path) if img_array is None: increment_processed_count(start_time, total_files) return if is_color_image(img_array): rel_path = path.relative_to(Config.INPUT_FOLDER) # Extract the original filename original_filename = rel_path.name # Apply renaming pattern to the original filename new_filename = renamer(app.RENAME_PATTERN.get(), original_filename) # Determine the new relative path with the renamed file new_rel_path = rel_path.with_name(new_filename) # Construct the full output path out_path = Config.OUTPUT_FOLDER / new_rel_path # Ensure that the parent directories exist out_path.parent.mkdir(parents=True, exist_ok=True) try: shutil.move(str(path), str(out_path)) except Exception as e: log_error(f"Failed to move {path} to {out_path}: {e}") increment_processed_count(start_time, total_files) return subfolder = str(rel_path.parent) # **Store the original filename instead of the new filename** image_processor.color_results[subfolder].append(original_filename) increment_processed_count(start_time, total_files) # --- Corrupted Files --- def check_for_corrupted_files() -> None: """Check for corrupted files in the input folder using FFmpeg.""" image_processor.reset_results() try: verify_executable_exists(Config.FFMPEG, "FFmpeg") except FileNotFoundError as error: log_error(str(error)) return valid_extensions: set[str] = ( Config.VIDEO_EXTENSIONS | Config.AUDIO_EXTENSIONS | Config.IMAGE_EXTENSIONS ) tasks: list[Path] = [ file for file in Config.INPUT_FOLDER.rglob("*") if file.is_file() and file.suffix.lower() in valid_extensions ] if not tasks: log_error(f"No valid media files found in '{Config.INPUT_FOLDER}'") return error_queue: Queue[tuple[Path, list[str]]] = Queue() start_time: float = time.time() total_files: int = len(tasks) def check_file(file_path: Path) -> None: try: base_command: list[str] = [ str(Config.FFMPEG), "-v", "error", "-i", str(file_path), ] if file_path.suffix.lower() in Config.VIDEO_EXTENSIONS: base_command += ["-map", "0:a:0"] base_command += ["-f", "null", "-"] result: subprocess.CompletedProcess = subprocess.run( base_command, capture_output=True, text=True, encoding="utf-8", errors="ignore", ) combined_output: str = f"{result.stdout}
{result.stderr}" error_messages: list[str] = [ line.strip() for line in combined_output.splitlines() if "error" in line.lower() ] if error_messages: error_queue.put((file_path.resolve(), error_messages)) except Exception as e: error_queue.put( (file_path.resolve(), [f"Error processing file {file_path}: {e}"]) ) finally: increment_processed_count(start_time, total_files) run_with_thread_pool(tasks, check_file) log_errors(error_queue) # --- Resize Images --- def resize_images( input_folder: Path, output_folder: Path, image_processor: "ImageProcessor" ) -> None: """Resize images in the input folder and save them to the output folder.""" try: verify_executable_exists(Config.IMAGEMAGICK, "ImageMagick") except FileNotFoundError as e: log_error(str(e)) return tasks: list[Path] = [ input_path for input_path in input_folder.rglob("*") if input_path.is_file() and input_path.suffix.lower() in Config.IMAGE_EXTENSIONS ] if not tasks: log_error(f"No image files found in '{input_folder}'") return with create_temp_folder() as temp_folder: run_with_thread_pool( tasks, process_file, time.time(), len(tasks), image_processor, temp_folder, True, ) def resize_image(input_path: Path, output_path: Path) -> Path: """Resize an image using ImageMagick.""" output_path = output_path.with_suffix(".png") identify_command = [ str(Config.IMAGEMAGICK), str(input_path), "-format", "%wx%h", "info:", ] try: result = subprocess.run( identify_command, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True, check=True, ) current_width, current_height = map(int, result.stdout.strip().split("x")) except subprocess.CalledProcessError as e: log_error(f"ImageMagick identify failed for {input_path}: {e.stderr.strip()}") return output_path resize_mode = app.RESIZE_MODE.get() maintain_aspect = app.maintain_aspect_ratio.get() if resize_mode == "Fit": target_width = int(app.RESIZE_WIDTH.get() or 0) target_height = int(app.RESIZE_HEIGHT.get() or 0) if maintain_aspect: if target_width == 0 and target_height > 0: target_width = int(target_height * current_width / current_height) elif target_height == 0 and target_width > 0: target_height = int(target_width * current_height / current_width) resize_arg = f"{target_width}x{target_height}!" else: # Shortest Side target_size = int(app.RESIZE_SIDE.get()) resize_arg = f"{target_size}x{target_size}^" is_upscaling = ( resize_mode == "Fit" and (target_width > current_width or target_height > current_height) ) or ( resize_mode == "Shortest Side" and target_size > min(current_width, current_height) ) command = [ str(Config.IMAGEMAGICK), str(input_path), ] if is_upscaling: command += [ "-filter", "LanczosSharp", "-distort", "Resize", resize_arg, ] else: command += [ "-colorspace", "RGB", "-filter", "Lanczos2Sharp", "-resize", resize_arg, "-colorspace", "sRGB", ] command += ["-define", "png:compression-level=5", str(output_path)] try: result = subprocess.run( command, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True, check=True, ) if result.stderr: log_error(f"ImageMagick: {result.stderr.strip()}") except subprocess.CalledProcessError as e: log_error(f"ImageMagick resize failed for {input_path}: {e.stderr.strip()}") return output_path # --- Processing --- def process_file( path: Path, start_time: float, total_files: int, image_processor: "ImageProcessor", temp_folder: Path, resize: bool = False, auto_correct_and_resize: bool = False, ) -> None: """Process a single image file.""" if shared_state.stop_event.is_set(): return img_array = load_image_as_array(path) if img_array is None: increment_processed_count(start_time, total_files) return relative_path = path.relative_to(Config.INPUT_FOLDER) temp_output_path = temp_folder / relative_path.with_suffix(".png") temp_output_path.parent.mkdir(parents=True, exist_ok=True) if auto_correct_and_resize: # Adjust and save image, then resize intermediate_path, _, _ = adjust_and_save_image( img_array, path, image_processor, temp_folder ) resized_path = resize_image(intermediate_path, temp_output_path) elif resize: # Only resize the original image resized_path = resize_image(path, temp_output_path) else: # Adjust and save image without resizing resized_path, _, _ = adjust_and_save_image( img_array, path, image_processor, temp_folder ) # Determine the final output format output_format = app.RESIZE_FORMAT.get().lower() if output_format not in ["jpg", "png"]: output_format = "png" # Fallback to PNG if an unsupported format is selected # Apply renaming pattern new_filename = renamer(app.RENAME_PATTERN.get(), relative_path.name) new_filename = os.path.splitext(new_filename)[0] + f".{output_format}" final_output_path = Config.OUTPUT_FOLDER / relative_path.parent / new_filename final_output_path.parent.mkdir(parents=True, exist_ok=True) # Save the final processed file if output_format == "jpg": convert_png_to_jpg(resized_path, final_output_path) else: shutil.move(str(resized_path), str(final_output_path)) increment_processed_count(start_time, total_files) def process_folder( folder: Path, image_processor: "ImageProcessor", auto_correct_and_resize: bool = False, ) -> None: """Process all images in a folder.""" image_processor.reset_results() if auto_correct_and_resize: try: verify_executable_exists(Config.IMAGEMAGICK, "ImageMagick") except FileNotFoundError as e: log_error(str(e)) return tasks: list[Path] = [ path for path in folder.rglob("*") if path.is_file() and path.suffix.lower() in Config.IMAGE_EXTENSIONS ] if not tasks: log_error(f"No image files found in '{folder}'") return with create_temp_folder() as temp_folder: run_with_thread_pool( tasks, process_file, time.time(), len(tasks), image_processor, temp_folder, False, auto_correct_and_resize, ) def adjust_and_save_image( img: np.ndarray, path: Path, image_processor: "ImageProcessor", temp_folder: Path, diff_threshold: int = Config.COLORDIFF_THRESHOLD, fraction_threshold: float = Config.FRACTION_COLORED_PIXELS_THRESHOLD, ) -> tuple[Path, Optional[int], Optional[int]]: """Process an image, adjusting and saving depending on whether it is color or grayscale.""" try: is_color = is_color_image(img, diff_threshold, fraction_threshold) relative_parent = path.parent.relative_to(Config.INPUT_FOLDER) out_path = temp_folder / relative_parent / f"{path.stem}.png" out_path.parent.mkdir(parents=True, exist_ok=True) subfolder = relative_parent.as_posix() filename = path.name if is_color: # Save color image as PNG Image.fromarray(img).save(out_path, format="PNG", compress_level=5) image_processor.color_results[subfolder].append(filename) return out_path, None, None # Load the image as grayscale before adjusting values img_gray = load_image_as_array(path, mode='L') if img_gray is None: log_error(f"Error loading image {path} as grayscale.") return out_path, None, None adjusted_img, modal_black, modal_white = adjust_grayscale_values(img_gray) Image.fromarray(adjusted_img).convert("L").save( out_path, format="PNG", compress_level=5 ) if modal_black: image_processor.black_results[subfolder].append((filename, modal_black)) if modal_white != 255: image_processor.white_results[subfolder].append((filename, modal_white)) return out_path, modal_black, modal_white except (OSError, ValueError) as e: log_error(f"Error processing image {path}: {e}") return path, None, None # --- ImageProcessor Class --- class ImageProcessor: """Class to handle image processing results.""" def __init__(self) -> None: self.white_results: dict[str, list[tuple[str, int]]] = defaultdict(list) self.black_results: dict[str, list[tuple[str, int]]] = defaultdict(list) self.color_results: dict[str, list[str]] = defaultdict(list) def collect_processing_results(self, output_folder: Path, choice: str) -> None: """Collect processing results and prepare them for display or logging.""" results_map: dict[str, Union[tuple[str, str, str], tuple[str, str]]] = { "2": ("2. Analyze Images", "Modal Value Black", "Modal Value White"), "3": ("3. Find Color Images", "Filename"), "5": ( "5. Automatic Color Correction", "Modal Value Black", "Modal Value White", ), "6": ( "6. Automatic Color Correction + Resize", "Modal Value Black", "Modal Value White", ), } headers = results_map.get(choice) if headers: if choice == "3": self._write_results("Color", self.color_results, headers[0], headers[1]) else: self._write_results("Black", self.black_results, headers[0], headers[1]) self._write_results("White", self.white_results, headers[0], headers[2]) self._write_results("Color", self.color_results, headers[0], "Filename") def _write_results( self, file_path: str, results: dict[str, Union[list[tuple[str, int]], list[str]]], header: str, value_name: str, ) -> None: """Write results to a specific file.""" separator = "-" * Config.SEPARATOR_LENGTH content = f"{separator}
{header}
{separator}
" if results: for subfolder, subfolder_results in sorted(results.items()): full_subfolder_path = Config.INPUT_FOLDER / subfolder content += f"
{full_subfolder_path}

" if value_name == "Filename": subfolder_results = cast(list[str], subfolder_results) subfolder_results.sort() content += "
".join( f" - {filename}" for filename in subfolder_results ) else: subfolder_results = cast(list[tuple[str, int]], subfolder_results) subfolder_results.sort(key=lambda x: x[1], reverse=True) content += "
".join( f" - {filename}, {value_name}: {value}" for filename, value in subfolder_results ) content += "
" shared_state.tab_messages[file_path].append(content) def reset_results(self) -> None: """Reset all results.""" self.white_results = defaultdict(list) self.black_results = defaultdict(list) self.color_results = defaultdict(list) # --- Tkinter App --- class App(tk.Tk): def __init__(self) -> None: super().__init__() self.setup_window() self.create_variables() self.create_widgets() self.setup_logging() self.process_start_time: float = 0.0 def setup_window(self) -> None: self.set_dpi_awareness() self.title("Image Processor") self.geometry("2100x1180") self.default_font = ("Roboto Flex", 16) self.apply_default_font() def set_dpi_awareness(self) -> None: try: ctypes.windll.shcore.SetProcessDpiAwareness(1) except Exception as e: print(f"Could not set DPI awareness: {e}") def apply_default_font(self) -> None: self.option_add("*Font", self.default_font) self.style = ttk.Style() for widget_type in [ "TButton", "TLabel", "TEntry", "TRadiobutton", "TNotebook.Tab", ]: self.style.configure(widget_type, font=self.default_font) self.style.configure("TFrame", background="#fdfdfd") self.style.configure("TLabel", background="#fdfdfd") self.style.configure("TNotebook", background="#f8f8f8") self.style.configure("TRadiobutton", background="#fdfdfd") def create_variables(self) -> None: self.RESIZE_MODE = tk.StringVar(value=Config.DEFAULT_RESIZE
